// Importing ethers.js library
import { ethers } from 'ethers';

// Function to connect to the Ethereum provider
async function connectToProvider() {
    if (window.ethereum) {
        try {
            // Request account access if needed
            await window.ethereum.request({ method: 'eth_requestAccounts' });
            // Create a new ethers.js provider
            const provider = new ethers.providers.Web3Provider(window.ethereum);
            return provider;
        } catch (error) {
            console.error("User denied account access", error);
        }
    } else {
        console.log("Non-Ethereum browser detected. You should consider trying MetaMask!");
    }
}

// Function to get the signer
async function getSigner(provider) {
    const signer = provider.getSigner();
    return signer;
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, params) {
    // Connect to the provider and get the signer
    const provider = await connectToProvider();
    const signer = await getSigner(provider);

    // Create an instance of the contract
    const contract = new ethers.Contract(contractAddress, abi, signer);

    try {
        // Call the function with provided parameters
        const transaction = await contract[functionName](...params);
        // Wait for the transaction to be mined
        await transaction.wait();
        console.log("Transaction successful:", transaction.hash);
    } catch (error) {
        console.error("Error interacting with contract", error);
    }
}

// Example usage
